// === Filtre Chatwoot V5 (identique a V4, valide en prod) ===
const item = $input.first()?.json ?? {};
const body = item.body ?? item;

if (body.event !== 'message_created') return [];

const isIncoming = body.message_type === 'incoming' || body.message_type === 0;
if (!isIncoming) return [];

const conversationId = body.conversation?.id;
if (!conversationId) return [];

const content = (body.content ?? '').toString().trim();
if (!content) return [];

const senderName = (body.sender?.name ?? 'prospect').toString().trim();
const senderEmail = (body.sender?.email ?? '').toString().trim();
const senderPhone = (body.sender?.phone_number ?? '').toString().trim();

return [
  {
    json: {
      conversation_id: conversationId,
      incoming_text: content,
      sender_name: senderName,
      sender_email: senderEmail,
      sender_phone: senderPhone,
      fallback_reply: "Bonjour et merci pour votre message. Pour bien vous orienter, pouvez-vous me preciser le nom de votre entreprise, votre secteur d'activite et votre besoin principal ?"
    }
  }
];

// === Build OpenAI reply payload (V5.5 Calendly conditionnel) ===
const historyResponse = $input.first()?.json ?? {};
const current = $('Filter Chatwoot event').first()?.json ?? {};

const MAX_HISTORY = 20;
const CALENDLY_URL = 'REPLACE_WITH_CALENDLY_URL';

function asArray(response) {
  if (Array.isArray(response)) return response;
  if (Array.isArray(response.payload)) return response.payload;
  if (Array.isArray(response.data)) return response.data;
  if (Array.isArray(response.messages)) return response.messages;
  return [];
}

const messages = asArray(historyResponse)
  .map((m) => {
    const content = (m.content ?? '').toString().trim();
    if (!content) return null;
    const isIn = m.message_type === 0 || m.message_type === 'incoming' || m.message_type === 3;
    const isOut = m.message_type === 1 || m.message_type === 'outgoing';
    if (!isIn && !isOut) return null;
    return { role: isIn ? 'user' : 'assistant', content, ts: m.created_at || 0 };
  })
  .filter(Boolean)
  .sort((a, b) => a.ts - b.ts)
  .slice(-MAX_HISTORY)
  .map(({ role, content }) => ({ role, content }));

const lastUserInHistory = [...messages].reverse().find((m) => m.role === 'user')?.content ?? '';
const alreadyIncluded = lastUserInHistory === current.incoming_text;

const knownName = (current.sender_name ?? '').toString().trim();
const knownEmail = (current.sender_email ?? '').toString().trim();
const knownPhone = (current.sender_phone ?? '').toString().trim();

const systemPrompt = [
  "Tu es l'assistant commercial de TransferAI Africa.",
  "Tu reponds exclusivement en francais, de facon claire, courte et professionnelle.",
  "Tu disposes de l'historique recent de la conversation et tu dois t'en servir pour eviter de reposer les memes questions.",
  "Quand une information a deja ete donnee, reutilise-la naturellement.",
  "Tu aides surtout les organisations en Afrique a avancer sur la formation IA, la veille strategique et l'automatisation.",
  "Tu accueilles chaleureusement le prospect, reformules son besoin si utile, puis poses au maximum 3 questions de qualification SEULEMENT si elles ne sont pas deja couvertes.",
  "Avant de proposer un creneau, un lien Calendly ou une demonstration, verifie d'abord si une adresse email de suivi est deja connue.",
  "Si aucune adresse email n'est connue, demande d'abord l'email du prospect puis attends sa reponse avant de proposer la suite de rendez-vous.",
  "Si l'email est deja connu dans les metadonnees ou l'historique, ne le redemande jamais.",
  "Tu peux proposer une demo avec lien Calendly SEULEMENT si le besoin est concret, B2B et suffisamment mature, ou si le prospect demande explicitement une demo.",
  "Quand tu proposes le lien, reste sobre, formule-le comme une option et utilise exactement le lien fourni dans le contexte systeme.",
  "Si les informations sont encore trop incomplètes, continue la qualification et ne propose pas encore de rendez-vous.",
  "Le telephone est secondaire : ne le demande que si cela aide concretement la suite.",
  "Ne promets jamais un prix, un delai ou un resultat non confirme.",
  "Reste concret, poli et utile. Maximum 5 lignes par reponse."
].join(' ');

const contactContext = [
  `Contact deja connu via Chatwoot :`,
  `- nom : ${knownName || 'non fourni'}`,
  `- email : ${knownEmail || 'non fourni'}`,
  `- telephone : ${knownPhone || 'non fourni'}`,
  `- lien Calendly a utiliser si pertinent : ${CALENDLY_URL}`
].join('\n');

const openaiMessages = [
  { role: 'system', content: systemPrompt },
  { role: 'system', content: contactContext },
  ...messages
];

if (!alreadyIncluded) {
  openaiMessages.push({ role: 'user', content: current.incoming_text });
}

return [
  {
    json: {
      conversation_id: current.conversation_id,
      incoming_text: current.incoming_text,
      sender_name: current.sender_name,
      sender_email: current.sender_email,
      sender_phone: current.sender_phone,
      fallback_reply: current.fallback_reply,
      history_count: messages.length,
      raw_history_messages: messages,
      openai_payload: {
        model: 'gpt-4.1-mini',
        temperature: 0.35,
        max_tokens: 350,
        messages: openaiMessages
      }
    }
  }
];

// === Format AI reply ===
const openai = $input.first()?.json ?? {};
const context = $('Build OpenAI reply payload').first()?.json ?? {};

const aiText = openai.choices?.[0]?.message?.content?.toString().trim();
const replyText = aiText || context.fallback_reply;

return [
  {
    json: {
      conversation_id: context.conversation_id,
      incoming_text: context.incoming_text,
      sender_name: context.sender_name,
      sender_email: context.sender_email,
      sender_phone: context.sender_phone,
      reply_text: replyText,
      used_fallback: !aiText,
      history_count: context.history_count ?? 0,
      raw_history_messages: context.raw_history_messages ?? []
    }
  }
];

// === Build qualification payload (deuxieme appel OpenAI dedie) ===
// On reprend l'historique complet (deja recupere par Fetch history) + le message courant,
// et on demande a OpenAI de produire UN JSON STRICT de qualification.

const format = $('Format AI reply').first()?.json ?? {};
const history = format.raw_history_messages ?? [];

// Composer la conversation en texte lisible pour le prompt
const conversationText = history
  .map((m) => `${m.role === 'user' ? 'PROSPECT' : 'ASSISTANT'}: ${m.content}`)
  .join('\n');

// Toujours s'assurer que le dernier message PROSPECT est inclus (au cas ou)
const lastUserText = [...history].reverse().find((m) => m.role === 'user')?.content ?? '';
const conversationFull = lastUserText === format.incoming_text
  ? conversationText
  : `${conversationText}\nPROSPECT: ${format.incoming_text}`;

const systemPrompt = [
  "Tu es un agent de qualification commerciale pour TransferAI Africa.",
  "Analyse la conversation ci-dessous et extrais STRICTEMENT un objet JSON valide.",
  "Ne renvoie QUE du JSON. Aucun texte autour, aucun markdown, aucun commentaire.",
  "",
  "Intentions possibles : formation, audit_ia, veille, automatisation, catalogue, certification, webinar, partenariat, emploi, support, autre.",
  "Niveaux de seriosite : faible, moyen, eleve.",
  "",
  "Regles :",
  "- utilise null si une information n'a JAMAIS ete donnee dans la conversation ou les metadonnees connues.",
  "- ne devine pas, n'invente pas.",
  "- 'is_b2b' = true si le prospect parle au nom d'une organisation, false si c'est un particulier, null sinon.",
  "- 'wants_demo' = true si le prospect a EXPLICITEMENT demande une demo, ou si l'assistant a propose une demo et le prospect a accepte.",
  "- 'needs_human_handoff' = true si la demande est strategique, sensible, tarifaire complexe, ou si le prospect demande un humain.",
  "- 'missing_fields' liste les champs parmi [company_name, sector, need_type] qui sont encore null.",
  "- si un email ou un telephone est connu via les metadonnees Chatwoot, reutilise-le.",
  "",
  "JSON attendu (TOUTES ces cles obligatoires) :",
  "{\"company_name\": null, \"sector\": null, \"need_type\": null, \"intent\": null, \"lead_seriousness\": null, \"is_b2b\": null, \"wants_demo\": null, \"needs_human_handoff\": null, \"contact_name\": null, \"email\": null, \"phone\": null, \"summary\": null, \"next_best_action\": null, \"missing_fields\": []}"
].join('\n');

const metadataBlock = [
  `Metadonnees connues hors texte :`,
  `- contact_name_chatwoot: ${format.sender_name || 'null'}`,
  `- sender_email_chatwoot: ${format.sender_email || 'null'}`,
  `- sender_phone_chatwoot: ${format.sender_phone || 'null'}`
].join('\n');

const userMessage = `${metadataBlock}\n\nConversation a analyser :\n\n${conversationFull || 'PROSPECT: ' + format.incoming_text}\n\nProduis le JSON.`;

return [
  {
    json: {
      conversation_id: format.conversation_id,
      incoming_text: format.incoming_text,
      sender_name: format.sender_name,
      sender_email: format.sender_email,
      sender_phone: format.sender_phone,
      reply_text: format.reply_text,
      qualification_payload: {
        model: 'gpt-4.1-mini',
        temperature: 0.1,
        max_tokens: 500,
        response_format: { type: 'json_object' },
        messages: [
          { role: 'system', content: systemPrompt },
          { role: 'user', content: userMessage }
        ]
      }
    }
  }
];

// === Parse qualification JSON + Compute custom_attributes + Compute labels ===
// Extrait le JSON de la reponse OpenAI, calcule les labels conditionnels,
// et prepare deux payloads : un pour les custom_attributes Chatwoot, un pour les labels.

const openai = $input.first()?.json ?? {};
const context = $('Build qualification payload').first()?.json ?? {};

// JSON par defaut si OpenAI a echoue ou renvoye un format invalide
const DEFAULT_QUALIFICATION = {
  company_name: null,
  sector: null,
  need_type: null,
  intent: null,
  lead_seriousness: null,
  is_b2b: null,
  wants_demo: null,
  needs_human_handoff: null,
  contact_name: null,
  email: null,
  phone: null,
  summary: null,
  next_best_action: null,
  missing_fields: ['company_name', 'sector', 'need_type']
};

let qualification = { ...DEFAULT_QUALIFICATION };
let parseError = null;

try {
  const raw = openai.choices?.[0]?.message?.content?.toString().trim() || '{}';
  const parsed = JSON.parse(raw);
  qualification = { ...DEFAULT_QUALIFICATION, ...parsed };
} catch (err) {
  parseError = err.message;
}

// Si on a recu le nom du sender via Chatwoot, on l'utilise comme fallback contact_name
if (!qualification.contact_name && context.sender_name && context.sender_name !== 'prospect') {
  qualification.contact_name = context.sender_name;
}
if (!qualification.email && context.sender_email) {
  qualification.email = context.sender_email;
}
if (!qualification.phone && context.sender_phone) {
  qualification.phone = context.sender_phone;
}

// === Calcul des labels Chatwoot conditionnels ===
const labels = [];
const intent = (qualification.intent || '').toString().toLowerCase();
if (intent === 'formation') labels.push('formation');
if (intent === 'audit_ia') labels.push('audit-ia');
if (intent === 'automatisation') labels.push('automatisation');
if (intent === 'partenariat') labels.push('partenariat');
if (intent === 'emploi') labels.push('emploi');
if (intent === 'catalogue') labels.push('catalogue');
if (intent === 'certification') labels.push('certification');
if (intent === 'webinar') labels.push('webinar');
if (intent === 'support') labels.push('support');
if (intent === 'veille') labels.push('veille');

const seriousness = (qualification.lead_seriousness || '').toString().toLowerCase();
if (seriousness === 'eleve' || seriousness === 'élevé' || seriousness === 'high') {
  labels.push('lead-chaud');
}

if (Array.isArray(qualification.missing_fields) && qualification.missing_fields.length > 0) {
  labels.push('infos-manquantes');
}

if (qualification.needs_human_handoff === true) {
  labels.push('handoff-humain');
}

if (qualification.wants_demo === true) {
  labels.push('demo-proposee');
}

// === Custom attributes a pousser dans Chatwoot ===
// On ne passe que les valeurs non-null pour ne pas ecraser des champs deja remplis avec des null
const customAttributes = {};
if (qualification.company_name) customAttributes.company_name = qualification.company_name;
if (qualification.sector) customAttributes.sector = qualification.sector;
if (qualification.need_type) customAttributes.need_type = qualification.need_type;
if (qualification.intent) customAttributes.intent = qualification.intent;
if (qualification.lead_seriousness) customAttributes.lead_seriousness = qualification.lead_seriousness;
if (qualification.summary) customAttributes.internal_summary = qualification.summary;
if (qualification.next_best_action) customAttributes.next_best_action = qualification.next_best_action;
if (qualification.email) customAttributes.lead_email = qualification.email;
if (qualification.phone) customAttributes.lead_phone = qualification.phone;
if (typeof qualification.is_b2b === 'boolean') customAttributes.is_b2b = qualification.is_b2b;
if (typeof qualification.wants_demo === 'boolean') customAttributes.demo_proposed = qualification.wants_demo;
if (typeof qualification.needs_human_handoff === 'boolean') customAttributes.human_handoff = qualification.needs_human_handoff;

return [
  {
    json: {
      conversation_id: context.conversation_id,
      qualification,
      labels,
      labels_count: labels.length,
      custom_attributes_payload: { custom_attributes: customAttributes },
      labels_payload: { labels },
      parse_error: parseError,
      qualification_used_fallback: parseError !== null
    }
  }
];
